<?php $this->extend('layouts.public'); $types=['box','car','boat','camper','caravan','horse_float','plant','tipper','commercial','other']; ?>
<?php $this->section('content'); ?>
<section class="section"><div class="container"><h1>Trailer marketplace</h1><form class="card" method="get" action="<?= e(url('marketplace')) ?>"><div class="grid grid-3"><div class="form-group"><label for="q">Search</label><input id="q" name="q" value="<?= e_attr($filters['q']) ?>" placeholder="Make, model or keyword"></div><div class="form-group"><label for="type">Trailer type</label><select id="type" name="type"><option value="">All types</option><?php foreach ($types as $type): ?><option value="<?= e_attr($type) ?>" <?= $filters['type']===$type?'selected':'' ?>><?= $this->e(ucwords(str_replace('_',' ',$type))) ?></option><?php endforeach; ?></select></div><div class="form-group"><label for="listing_type">Availability</label><select id="listing_type" name="listing_type"><option value="">Sale or hire</option><?php foreach (['new'=>'New','used'=>'Used','hire'=>'Hire'] as $key=>$label): ?><option value="<?= e_attr($key) ?>" <?= $filters['listing_type']===$key?'selected':'' ?>><?= $this->e($label) ?></option><?php endforeach; ?></select></div></div><button class="btn btn-primary" type="submit">Search marketplace</button></form>
<?php if (empty($listings)): ?><div class="card"><p>No trailers match those filters yet.</p></div><?php else: ?><div class="grid grid-3"><?php foreach ($listings as $listing): ?><article class="card"><span class="badge badge-neutral"><?= $this->e(ucwords(str_replace('_',' ',$listing['trailer_type']))) ?></span><h2><a href="<?= e(url('trailers/'.$listing['slug'])) ?>"><?= $this->e($listing['title']) ?></a></h2><p><?= $this->e($listing['business_name']) ?><?php if (!empty($listing['location_text'])): ?> · <?= $this->e($listing['location_text']) ?><?php endif; ?></p><?php if ($listing['price_aud'] !== null): ?><p><strong>$<?= number_format((float)$listing['price_aud'],0) ?></strong></p><?php endif; ?></article><?php endforeach; ?></div><?php endif; ?></div></section>
<?php $this->endSection(); ?>
